const payload = $input.first().json;
const body = payload.body ?? payload;

const phone = String(body.phone_number ?? '').replace(/\D/g, '');
const text = String(body.message_body ?? body.text ?? '').trim();
const mediaUrl = body.media_url ?? null;
const mediaType = body.media_type ?? 'image';
const mimeType = body.media_mimetype ?? body.mimetype ?? null;
let fileName = body.media_file_name ?? body.fileName ?? null;

if (!phone) {
  throw new Error('phone_number vazio no payload outbound');
}

if (!text && !mediaUrl) {
  throw new Error('message_body ou media_url obrigatório no payload outbound');
}

function inferMime(url, type) {
  const lower = String(url).toLowerCase();
  if (lower.includes('.jpeg') || lower.includes('.jpg')) return 'image/jpeg';
  if (lower.includes('.png')) return 'image/png';
  if (lower.includes('.webp')) return 'image/webp';
  if (lower.includes('.gif')) return 'image/gif';
  if (lower.includes('.pdf')) return 'application/pdf';
  if (type === 'image') return 'image/jpeg';
  if (type === 'document') return 'application/pdf';
  return 'application/octet-stream';
}

function inferFileName(url, type) {
  const segment = String(url).split('/').pop()?.split('?')[0];
  if (segment && segment.includes('.')) return segment;
  if (type === 'document') return 'documento.pdf';
  return 'imagem.jpg';
}

const resolvedMime = mimeType || (mediaUrl ? inferMime(mediaUrl, mediaType) : null);
const resolvedFileName = fileName || (mediaUrl ? inferFileName(mediaUrl, mediaType) : null);
const evolutionMediaType =
  mediaType === 'document' ? 'document' :
  mediaType === 'video' ? 'video' :
  mediaType === 'audio' ? 'audio' : 'image';

return [{
  json: {
    phone_number: phone,
    number: phone,
    text,
    message_body: text,
    source: body.source ?? 'site-record',
    media_type: mediaType,
    media_url: mediaUrl,
    media_mimetype: resolvedMime,
    media_file_name: resolvedFileName,
    evolution_mediatype: evolutionMediaType,
    has_media: Boolean(mediaUrl),
  }
}];
